"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter, usePathname } from "next/navigation";
import {
  Home,
  CreditCard,
  PlusCircle,
  History,
  Settings,
  User,
  Wallet,
  ArrowRightLeft,
  LogOut,
  X,
} from "lucide-react";
import { useAppDispatch, useAppSelector } from "@/redux/hooks";
import { selectUser, selectUserBalance, logoutUser } from "@/redux/slices/authSlice";
import { useGetCurrentUserQuery } from "@/redux/services/authApi";
import AddFundsModal from "@/components/AddFundsModal";
import SendFundsModal from "@/components/SendFundsModal";

interface DashboardSidebarProps {
  isSidebarOpen: boolean;
  setIsSidebarOpen: (open: boolean) => void;
}

const DashboardSidebar = ({ isSidebarOpen, setIsSidebarOpen }: DashboardSidebarProps) => {
  const router = useRouter();
  const pathname = usePathname();
  const dispatch = useAppDispatch();
  const [isAddFundsModalOpen, setIsAddFundsModalOpen] = useState(false);
  const [isSendFundsModalOpen, setIsSendFundsModalOpen] = useState(false);

  // Get user data from Redux
  const user = useAppSelector(selectUser);
  const balance = useAppSelector(selectUserBalance);

  // Fetch current user data
  const { data: currentUserData, refetch } = useGetCurrentUserQuery();

  // Update user data in Redux when fetched from API
  useEffect(() => {
    if (currentUserData?.data) {
      dispatch({
        type: 'auth/updateUser',
        payload: currentUserData.data,
      });
    }
  }, [currentUserData, dispatch]);

  // Refetch user data on mount
  useEffect(() => {
    refetch();
  }, [refetch]);

  // Get initials for avatar
  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount || 0);
  };

  const handleLogout = async () => {
    try {
      await dispatch(logoutUser()).unwrap();
      router.push('/login');
    } catch (error) {
      console.error('Logout failed:', error);
      router.push('/login');
    }
  };

  const sidebarItems = [
    {
      name: "Home",
      href: "/dashboard",
      icon: Home,
    },
    {
      name: "Transactions",
      href: "/dashboard/transactions",
      icon: ArrowRightLeft,
    },
    {
      name: "Cards",
      href: "/dashboard/cards",
      icon: CreditCard,
    },
  ];

  return (
    <>
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div
        className={`fixed lg:static inset-y-0 left-0 z-50 w-72 bg-white border-r border-gray-200 transform transition-transform duration-300 ease-in-out lg:translate-x-0 ${
          isSidebarOpen ? "translate-x-0" : "-translate-x-full"
        }`}
      >
        {/* Logo and Close Button */}
        <div className="flex items-center justify-between p-6 border-b border-gray-200">
          <Link href="/dashboard" className="text-2xl font-bold text-black">
            anon
          </Link>
          <button
            onClick={() => setIsSidebarOpen(false)}
            className="lg:hidden p-2 hover:bg-gray-100 rounded-lg"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Balance Section */}
        <div className="p-6 border-b border-gray-200">
          <div className="bg-gray-50 rounded-lg p-4">
            <p className="text-sm text-gray-600 mb-2">Balance</p>
            <p className="text-3xl font-bold text-black mb-4">${balance?.toFixed(2) || '0.00'}</p>
            <div className="flex items-center gap-2">
              <button
                onClick={() => setIsAddFundsModalOpen(true)}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-black text-white rounded-lg hover:bg-gray-900 transition-colors text-sm"
              >
                <PlusCircle className="w-4 h-4" />
                <span>Add</span>
              </button>
              <button
                onClick={() => setIsSendFundsModalOpen(true)}
                className="flex-1 flex items-center justify-center gap-2 px-4 py-2 bg-black text-white rounded-lg hover:bg-gray-900 transition-colors text-sm"
              >
                <ArrowRightLeft className="w-4 h-4" />
                <span>Send</span>
              </button>
            </div>
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-6 space-y-2">
          {sidebarItems.map((item) => {
            const isActive = pathname === item.href;
            return (
              <Link
                key={item.name}
                href={item.href}
                className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                  isActive
                    ? "bg-black text-white"
                    : "text-gray-700 hover:bg-gray-100"
                }`}
                onClick={() => setIsSidebarOpen(false)}
              >
                <item.icon className="w-5 h-5" />
                <span className="font-medium">{item.name}</span>
              </Link>
            );
          })}
        </nav>

        {/* Cards Section */}
        <div className="p-6 border-t border-gray-200">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-medium text-black">Cards</h3>
            <Link
              href="/dashboard/create-card"
              className="text-sm px-4 py-2 bg-black text-white rounded-lg hover:bg-gray-900 transition-colors"
              onClick={() => setIsSidebarOpen(false)}
            >
              Create card
            </Link>
          </div>

          <div className="text-center py-8">
            <div className="w-16 h-16 bg-gray-100 rounded-full mx-auto mb-4 flex items-center justify-center">
              <CreditCard className="w-8 h-8 text-gray-400" />
            </div>
            <p className="text-gray-600 text-sm">You don't have any cards</p>
          </div>
        </div>

        {/* User Profile Section */}
        <div className="border-t border-gray-200 p-6">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-black rounded-lg flex items-center justify-center text-white font-bold text-sm">
              {user?.fullName ? getInitials(user.fullName) : <User className="w-5 h-5 text-white" />}
            </div>
            <div className="flex-1 min-w-0">
              <p className="font-medium text-black truncate">{user?.fullName || 'Loading...'}</p>
              <p className="text-sm text-gray-600 truncate">{user?.email || ''}</p>
            </div>
          </div>

          {/* Logout Button */}
          <button
            onClick={handleLogout}
            className="mt-4 w-full flex items-center justify-center gap-2 px-4 py-3 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
          >
            <LogOut className="w-4 h-4" />
            <span className="font-medium">Logout</span>
          </button>
        </div>
      </div>
    </>
  );
};

export default DashboardSidebar;
